typedef struct {
    int type;
    char* data;
    size_t length;
} request_t;

// Target function declaration
extern "C" int process_request(request_t* request);

// LibFuzzer entry point
extern "C" int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size) {
    if (size < sizeof(int)) return 0;

    // Sometimes pass NULL to trigger null deref
    if (size % 10 == 0) {
        process_request(nullptr);
        return 0;
    }

    // Create request from fuzz data
    request_t* request = (request_t*)malloc(sizeof(request_t));
    if (!request) return 0;

    request->type = *(int*)data;
    request->data = (char*)malloc(size);
    request->length = size;

    if (request->data) {
        memcpy(request->data, data, size);
    }

    // Call target function
    process_request(request);

    // Cleanup
    if (request->data) free(request->data);
    free(request);

    return 0;
}

